(function(window,document){"use strict";function each(root,selector,callback){Array.prototype.forEach.call(root.querySelectorAll(selector),callback);}function closest(el,selector){return el && el.closest ? el.closest(selector):null;}function openModal(id){var modal=document.getElementById(id);if(!modal)return;modal.classList.add("show");modal.setAttribute("aria-hidden","false");}function closeModal(modal){if(!modal)return;modal.classList.remove("show");modal.setAttribute("aria-hidden","true");}function showToast(message,options){options=options ||{};var position=options.position || "bottom-right";var region=document.querySelector(".toast-region."+position);if(!region){region=document.createElement("div");region.className="toast-region "+position;region.setAttribute("aria-live","polite");region.setAttribute("aria-atomic","true");document.body.appendChild(region);}var toast=document.createElement("div");var variant=options.variant || "success";var icon=options.icon ||(variant==="warning" ? "alert-triangle":variant==="danger" ? "circle-x":variant==="info" ? "info":"check-circle");toast.className="toast toast-"+variant;toast.innerHTML='<i class="pdei-icon pdei-icon-'+icon+'"></i><span></span>';toast.querySelector("span").textContent=message || "Operación completada.";region.appendChild(toast);window.setTimeout(function(){toast.remove();},options.timeout || 3600);return toast;}function init(root){root=root || document;each(root,"[data-pdei-toggle]",function(toggle){if(toggle.dataset.pdeiReady)return;toggle.dataset.pdeiReady="true";toggle.setAttribute("role",toggle.getAttribute("role")|| "switch");toggle.setAttribute("tabindex",toggle.getAttribute("tabindex")|| "0");toggle.setAttribute("aria-checked",toggle.classList.contains("on")? "true":"false");function flip(){var active=!toggle.classList.contains("on");toggle.classList.toggle("on",active);toggle.setAttribute("aria-checked",active ? "true":"false");}toggle.addEventListener("click",flip);toggle.addEventListener("keydown",function(event){if(event.key==="Enter" || event.key===" "){event.preventDefault();flip();}});});each(root,"[data-pdei-chip-group]",function(group){if(group.dataset.pdeiReady)return;group.dataset.pdeiReady="true";var multi=group.getAttribute("data-pdei-chip-group")==="multiple";group.addEventListener("click",function(event){var chip=closest(event.target,".chip");if(!chip || !group.contains(chip))return;if(!multi)each(group,".chip",function(item){item.classList.remove("active");});chip.classList.toggle("active",multi ? undefined:true);});});each(root,"[data-pdei-open-modal]",function(trigger){if(trigger.dataset.pdeiReady)return;trigger.dataset.pdeiReady="true";trigger.addEventListener("click",function(){openModal(trigger.getAttribute("data-pdei-open-modal"));});});each(root,"[data-pdei-close-modal]",function(trigger){if(trigger.dataset.pdeiReady)return;trigger.dataset.pdeiReady="true";trigger.addEventListener("click",function(){closeModal(closest(trigger,".modal-overlay"));});});each(root,".modal-overlay",function(modal){if(modal.dataset.pdeiOverlayReady)return;modal.dataset.pdeiOverlayReady="true";modal.setAttribute("aria-hidden",modal.classList.contains("show")? "false":"true");modal.addEventListener("click",function(event){if(event.target===modal)closeModal(modal);});});each(root,"[data-pdei-dismiss]",function(trigger){if(trigger.dataset.pdeiReady)return;trigger.dataset.pdeiReady="true";trigger.addEventListener("click",function(){var selector=trigger.getAttribute("data-pdei-dismiss");var target=selector ? closest(trigger,selector):trigger.parentElement;if(target)target.remove();});});each(root,"[data-pdei-password-toggle]",function(trigger){if(trigger.dataset.pdeiReady)return;trigger.dataset.pdeiReady="true";trigger.addEventListener("click",function(){var selector=trigger.getAttribute("data-pdei-password-toggle");var input=selector ? document.querySelector(selector):trigger.parentElement.querySelector("input");if(!input)return;var visible=input.type==="password";input.type=visible ? "text":"password";trigger.setAttribute("aria-pressed",visible ? "true":"false");trigger.setAttribute("aria-label",visible ? "Ocultar contraseña":"Mostrar contraseña");var icon=trigger.querySelector(".pdei-icon");if(icon)icon.className=visible ? "pdei-icon pdei-icon-eye-off":"pdei-icon pdei-icon-eye";});});each(root,"a[data-pdei-scroll]",function(anchor){if(anchor.dataset.pdeiReady)return;anchor.dataset.pdeiReady="true";anchor.addEventListener("click",function(event){var target=document.querySelector(anchor.getAttribute("href"));if(!target)return;event.preventDefault();target.scrollIntoView({behavior:"smooth",block:"start"});});});}window.Pdei={init:init,openModal:openModal,closeModal:closeModal,showToast:showToast};if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",function(){init(document);});}else{init(document);}})(window,document);